"use client"

import * as React from "react"
import { Button } from "@/components/ui/button"

export interface LemmaBulkActionsBarProps {
  selectedCount: number
  title?: string
  description?: string
  isDeleting?: boolean
  deleteLabel?: string
  clearLabel?: string
  onDeleteSelected?: () => void
  onClearSelection?: () => void
  error?: Error | null
  message?: string | null
}

export function LemmaBulkActionsBar({
  selectedCount,
  title = "Bulk actions",
  description = "Select multiple rows to run a single action across them.",
  isDeleting = false,
  deleteLabel = "Delete selected",
  clearLabel = "Clear selection",
  onDeleteSelected,
  onClearSelection,
  error,
  message,
}: LemmaBulkActionsBarProps) {
  if (selectedCount <= 0 && !error && !message) return null

  return (
    <div className="grid gap-3 rounded-[var(--resource-radius-md)] border border-[color:var(--resource-border)] bg-[var(--resource-surface)] p-4 shadow-sm">
      <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div className="grid gap-1">
          <div className="text-sm font-medium text-[color:var(--resource-text)]">{title}</div>
          <div className="text-sm text-[color:var(--resource-muted)]">
            {selectedCount > 0
              ? `${selectedCount} record${selectedCount === 1 ? "" : "s"} selected. ${description}`
              : description}
          </div>
        </div>
        {selectedCount > 0 ? (
          <div className="flex items-center gap-2">
            {onClearSelection ? (
              <Button onClick={onClearSelection} variant="ghost">
                {clearLabel}
              </Button>
            ) : null}
            {onDeleteSelected ? (
              <Button disabled={isDeleting} onClick={onDeleteSelected}>
                {isDeleting ? "Deleting…" : deleteLabel}
              </Button>
            ) : null}
          </div>
        ) : null}
      </div>

      {error ? (
        <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
          {error.message}
        </div>
      ) : null}

      {message ? (
        <div className="rounded-md border border-[color:var(--resource-border-strong)] bg-[var(--resource-surface-alt)] px-3 py-2 text-sm text-[color:var(--resource-text)]">
          {message}
        </div>
      ) : null}
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecord } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"

export interface LemmaRecordDetailsCardProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  fields?: string[]
  title?: string
  description?: string
}

function sentenceCase(value: string): string {
  return value
    .replace(/_/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export function LemmaRecordDetailsCard({
  client,
  podId,
  tableName,
  recordId,
  fields,
  title,
  description,
}: LemmaRecordDetailsCardProps) {
  const trimmedTableName = tableName.trim()
  const trimmedRecordId = typeof recordId === "string" ? recordId.trim() : ""
  const recordState = useRecord({
    client,
    podId,
    tableName: trimmedTableName,
    recordId: trimmedRecordId || null,
    enabled: trimmedTableName.length > 0 && trimmedRecordId.length > 0,
  })

  const visibleFields = React.useMemo(() => {
    const record = recordState.record
    if (!record) return fields ?? []
    if (fields?.length) return fields
    return Object.keys(record)
      .filter((field) => field !== "created_at" && field !== "updated_at")
      .slice(0, 12)
  }, [fields, recordState.record])

  if (!trimmedTableName || !trimmedRecordId) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Record Details"}</CardTitle>
          <CardDescription>{description ?? "Select a record to inspect its full payload."}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title ?? "Record Details"}</CardTitle>
            <CardDescription>{description ?? "Inspect the selected record with real values."}</CardDescription>
          </div>
          <Button
            disabled={recordState.isLoading}
            onClick={() => {
              void recordState.refresh()
            }}
            variant="outline"
          >
            {recordState.isLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-4">
        {recordState.error ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {recordState.error.message}
          </div>
        ) : null}

        {recordState.isLoading && !recordState.record ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            Loading record details…
          </div>
        ) : null}

        {recordState.record ? (
          <div className="grid gap-3">
            {visibleFields.map((field) => (
              <div key={field} className="rounded-[calc(var(--resource-radius-md)-0.2rem)] border border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-3">
                <div className="text-xs uppercase tracking-[0.16em] text-[color:var(--resource-subtle)]">{sentenceCase(field)}</div>
                <pre className="mt-2 whitespace-pre-wrap text-sm leading-6 text-[color:var(--resource-text)]">
                  {formatValue(recordState.record?.[field])}
                </pre>
              </div>
            ))}
          </div>
        ) : null}
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecordForm } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { LemmaForeignKeySelect } from "@/components/lemma/lemma-foreign-key-select"

export interface LemmaRecordFormProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  initialValues?: Record<string, unknown>
  mode?: "auto" | "create" | "update"
  title?: string
  description?: string
  submitLabel?: string
  hiddenFields?: string[]
  fieldOrder?: string[]
  onSubmitted?: (record: Record<string, unknown>) => void
}

function orderFields(
  fields: Array<ReturnType<typeof useRecordForm>["editableFields"][number]>,
  fieldOrder?: string[],
) {
  if (!fieldOrder?.length) return fields

  const indexByName = new Map(fieldOrder.map((name, index) => [name, index]))

  return [...fields].sort((left, right) => {
    const leftIndex = indexByName.get(left.name)
    const rightIndex = indexByName.get(right.name)

    if (typeof leftIndex === "number" && typeof rightIndex === "number") {
      return leftIndex - rightIndex
    }

    if (typeof leftIndex === "number") return -1
    if (typeof rightIndex === "number") return 1
    return left.label.localeCompare(right.label)
  })
}

export function LemmaRecordForm({
  client,
  podId,
  tableName,
  recordId,
  initialValues,
  mode = "auto",
  title,
  description,
  submitLabel = recordId ? "Save changes" : "Create record",
  hiddenFields = [],
  fieldOrder,
  onSubmitted,
}: LemmaRecordFormProps) {
  const hasTableName = tableName.trim().length > 0

  const form = useRecordForm({
    client,
    podId,
    tableName,
    recordId,
    initialValues,
    mode,
    onSubmitSuccess: (record) => onSubmitted?.(record),
  })

  const fields = React.useMemo(() => {
    const visibleFields = form.editableFields.filter((field) => !hiddenFields.includes(field.name))
    return orderFields(visibleFields, fieldOrder)
  }, [fieldOrder, form.editableFields, hiddenFields])

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  if (!hasTableName) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Registry Record Form"}</CardTitle>
          <CardDescription>
            {description ?? "Select a table to render the generated record form."}
          </CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>{title ?? `${recordId ? "Edit" : "Create"} ${tableName}`}</CardTitle>
        <CardDescription>
          {description ?? "Schema-aware form powered by lemma-sdk/react."}
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form className="grid gap-4" onSubmit={handleSubmit}>
          {form.error ? (
            <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
              {form.error.message}
            </div>
          ) : null}

          {form.isLoadingSchema || form.isLoadingRecord ? (
            <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
              Loading form…
            </div>
          ) : null}

          {!form.isLoadingSchema && !form.isLoadingRecord && fields.length === 0 ? (
            <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
              No editable fields were found for this table.
            </div>
          ) : null}

          {fields.map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const commonLabel = (
              <div className="grid gap-1.5">
                <Label htmlFor={field.name}>
                  {field.label}
                  {field.required ? " *" : ""}
                </Label>
                {field.column.description ? (
                  <p className="text-sm text-[color:var(--resource-muted)]">{field.column.description}</p>
                ) : null}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="grid gap-2 rounded-lg border border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] p-3">
                  {commonLabel}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span>{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option} value={option}>
                          {option}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "foreign-key") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <LemmaForeignKeySelect
                    client={client}
                    podId={podId}
                    tableName={tableName}
                    columnName={field.name}
                    value={typeof value === "string" ? value : value ? String(value) : ""}
                    onValueChange={(nextValue: string) => form.setValue(field.name, nextValue)}
                  />
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Textarea
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {commonLabel}
                <Input
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex items-center gap-2 pt-2">
            <Button disabled={form.isSubmitting || form.isLoadingSchema || form.isLoadingRecord} type="submit">
              {form.isSubmitting ? "Saving…" : submitLabel}
            </Button>
            <Button
              disabled={form.isSubmitting}
              onClick={() => form.reset()}
              type="button"
              variant="outline"
            >
              Reset
            </Button>
          </div>
        </form>
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecords } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

export interface LemmaRecordPickerProps {
  client: LemmaClient
  podId?: string
  tableName: string
  value?: string
  onValueChange?: (value: string) => void
  title?: string
  description?: string
  placeholder?: string
  search?: string
  onSearchChange?: (value: string) => void
  searchPlaceholder?: string
  searchFields?: string[]
  labelFields?: string[]
  limit?: number
  records?: Record<string, unknown>[]
  isLoading?: boolean
  error?: Error | null
  onRefresh?: () => void
}

const EMPTY_LABEL_FIELDS: string[] = []

function summarizeRecord(record: Record<string, unknown>, labelFields: string[]): string {
  const candidates = [
    ...labelFields,
    "title",
    "name",
    "label",
    "email",
    "id",
  ]

  for (const field of candidates) {
    const value = record[field]
    if (typeof value === "string" && value.trim().length > 0) return value
    if (typeof value === "number") return String(value)
  }

  try {
    return JSON.stringify(record)
  } catch {
    return "Untitled record"
  }
}

export function LemmaRecordPicker({
  client,
  podId,
  tableName,
  value,
  onValueChange,
  title = "Record Picker",
  description = "Jump to a specific record in the selected table.",
  placeholder = "Select a record",
  search,
  onSearchChange,
  searchPlaceholder = "Search loaded records…",
  searchFields,
  labelFields = EMPTY_LABEL_FIELDS,
  limit = 50,
  records,
  isLoading,
  error,
  onRefresh,
}: LemmaRecordPickerProps) {
  const [internalSearch, setInternalSearch] = React.useState("")
  const activeSearch = search ?? internalSearch
  const deferredSearch = React.useDeferredValue(activeSearch)
  const trimmedTableName = tableName.trim()
  const recordsState = useRecords({
    client,
    podId,
    tableName: trimmedTableName,
    enabled: trimmedTableName.length > 0 && !records,
    limit,
  })

  const effectiveRecords = records ?? recordsState.records
  const effectiveIsLoading = isLoading ?? recordsState.isLoading
  const effectiveError = error ?? recordsState.error

  const filteredRecords = React.useMemo(() => {
    const normalizedSearch = deferredSearch.trim().toLowerCase()
    if (!normalizedSearch) return effectiveRecords

    const fields = searchFields?.length
      ? searchFields
      : Array.from(new Set([...labelFields, "title", "name", "label", "email", "id"]))

    return effectiveRecords.filter((record) => fields.some((field) => {
      const fieldValue = record[field]
      if (typeof fieldValue === "string") return fieldValue.toLowerCase().includes(normalizedSearch)
      if (typeof fieldValue === "number" || typeof fieldValue === "boolean") {
        return String(fieldValue).toLowerCase().includes(normalizedSearch)
      }
      return false
    }))
  }, [deferredSearch, effectiveRecords, labelFields, searchFields])

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title}</CardTitle>
            <CardDescription>{description}</CardDescription>
          </div>
          <Button
            disabled={effectiveIsLoading || trimmedTableName.length === 0}
            onClick={() => {
              if (onRefresh) {
                onRefresh()
                return
              }
              void recordsState.refresh()
            }}
            variant="outline"
          >
            {effectiveIsLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-3">
        {effectiveError ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {effectiveError.message}
          </div>
        ) : null}

        <Input
          onChange={(event) => {
            if (onSearchChange) {
              onSearchChange(event.target.value)
              return
            }
            setInternalSearch(event.target.value)
          }}
          placeholder={searchPlaceholder}
          value={activeSearch}
        />

        <Select
          disabled={trimmedTableName.length === 0 || filteredRecords.length === 0}
          value={value ?? ""}
          onValueChange={onValueChange}
        >
          <SelectTrigger id="lemma-record-picker">
            <SelectValue placeholder={placeholder} />
          </SelectTrigger>
          <SelectContent>
            {filteredRecords.map((record) => {
              const id = typeof record.id === "string" ? record.id : String(record.id ?? "")
              return (
                <SelectItem key={id} value={id}>
                  {summarizeRecord(record, labelFields)}
                </SelectItem>
              )
            })}
          </SelectContent>
        </Select>

        <p className="text-xs text-[color:var(--resource-muted)]">
          {trimmedTableName.length === 0
            ? "Select a table first."
            : `${filteredRecords.length} record${filteredRecords.length === 1 ? "" : "s"} available`}
        </p>
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecords, useTable } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"

export interface LemmaRecordsTableProps {
  client: LemmaClient
  podId?: string
  tableName: string
  title?: string
  description?: string
  limit?: number
  records?: Record<string, unknown>[]
  isLoading?: boolean
  error?: Error | null
  onRefresh?: () => void
  columnNames?: string[]
  maxColumns?: number
  search?: string
  searchFields?: string[]
  selectedRecordId?: string | null
  recordIdField?: string
  emptyText?: string
  onRowSelect?: (record: Record<string, unknown>) => void
  showSelection?: boolean
  selectedRecordIds?: string[]
  onSelectedRecordIdsChange?: (recordIds: string[]) => void
  pageIndex?: number
  pageSize?: number
  totalCount?: number
  hasNextPage?: boolean
  onPreviousPage?: () => void
  onNextPage?: () => void
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function getRecordId(record: Record<string, unknown>, recordIdField: string): string {
  const value = record[recordIdField]
  if (typeof value === "string") return value
  if (typeof value === "number") return String(value)
  return ""
}

export function LemmaRecordsTable({
  client,
  podId,
  tableName,
  title,
  description,
  limit = 10,
  records,
  isLoading,
  error,
  onRefresh,
  columnNames,
  maxColumns = 6,
  search,
  searchFields,
  selectedRecordId,
  recordIdField = "id",
  emptyText = "No records found for this table.",
  onRowSelect,
  showSelection = false,
  selectedRecordIds,
  onSelectedRecordIdsChange,
  pageIndex = 0,
  pageSize = limit,
  totalCount,
  hasNextPage = false,
  onPreviousPage,
  onNextPage,
}: LemmaRecordsTableProps) {
  const trimmedTableName = tableName.trim()
  const tableState = useTable({
    client,
    podId,
    tableName: trimmedTableName,
    enabled: trimmedTableName.length > 0,
  })
  const recordsState = useRecords({
    client,
    podId,
    tableName: trimmedTableName,
    enabled: trimmedTableName.length > 0 && !records,
    limit,
  })
  const effectiveRecords = records ?? recordsState.records
  const effectiveIsLoading = isLoading ?? recordsState.isLoading
  const effectiveError = error ?? recordsState.error
  const deferredSearch = React.useDeferredValue(search ?? "")

  const visibleColumns = React.useMemo(() => {
    if (columnNames?.length) return columnNames

    const schemaColumns = tableState.table?.columns
      .map((column) => column.name)
      .filter((name) => name !== "created_at" && name !== "updated_at")

    if (schemaColumns && schemaColumns.length > 0) {
      return schemaColumns.slice(0, maxColumns)
    }

    const discoveredKeys = Array.from(
      new Set(effectiveRecords.flatMap((record) => Object.keys(record))),
    )

    return discoveredKeys.slice(0, maxColumns)
  }, [columnNames, effectiveRecords, maxColumns, tableState.table])

  const filteredRecords = React.useMemo(() => {
    const normalizedSearch = deferredSearch.trim().toLowerCase()
    if (!normalizedSearch) return effectiveRecords

    const activeSearchFields = searchFields?.length
      ? searchFields
      : visibleColumns

    return effectiveRecords.filter((record) => activeSearchFields.some((field) => {
      const value = record[field]
      if (typeof value === "string") return value.toLowerCase().includes(normalizedSearch)
      if (typeof value === "number" || typeof value === "boolean") {
        return String(value).toLowerCase().includes(normalizedSearch)
      }
      return false
    }))
  }, [deferredSearch, effectiveRecords, searchFields, visibleColumns])

  const selectedIdSet = React.useMemo(
    () => new Set(selectedRecordIds ?? []),
    [selectedRecordIds],
  )
  const visibleSelectableIds = React.useMemo(
    () => filteredRecords
      .map((record) => getRecordId(record, recordIdField))
      .filter((value) => value.length > 0),
    [filteredRecords, recordIdField],
  )
  const allVisibleSelected = visibleSelectableIds.length > 0
    && visibleSelectableIds.every((recordId) => selectedIdSet.has(recordId))
  const selectionEnabled = showSelection && !!onSelectedRecordIdsChange
  const resolvedTotalCount = typeof totalCount === "number" ? totalCount : filteredRecords.length
  const rangeStart = resolvedTotalCount === 0 ? 0 : (pageIndex * pageSize) + 1
  const rangeEnd = Math.min((pageIndex * pageSize) + filteredRecords.length, resolvedTotalCount)

  const toggleRecordSelection = React.useCallback((recordId: string, checked: boolean) => {
    if (!onSelectedRecordIdsChange) return

    const nextSelection = new Set(selectedRecordIds ?? [])
    if (checked) {
      nextSelection.add(recordId)
    } else {
      nextSelection.delete(recordId)
    }
    onSelectedRecordIdsChange(Array.from(nextSelection))
  }, [onSelectedRecordIdsChange, selectedRecordIds])

  const toggleVisibleSelection = React.useCallback((checked: boolean) => {
    if (!onSelectedRecordIdsChange) return

    const nextSelection = new Set(selectedRecordIds ?? [])
    visibleSelectableIds.forEach((recordId) => {
      if (checked) {
        nextSelection.add(recordId)
      } else {
        nextSelection.delete(recordId)
      }
    })
    onSelectedRecordIdsChange(Array.from(nextSelection))
  }, [onSelectedRecordIdsChange, selectedRecordIds, visibleSelectableIds])

  if (!trimmedTableName) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Records Table"}</CardTitle>
          <CardDescription>{description ?? "Select a table to preview its records."}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title ?? `Records: ${trimmedTableName}`}</CardTitle>
            <CardDescription>
              {description ?? `Preview the latest ${limit} records from this table.`}
            </CardDescription>
          </div>
          <Button
            disabled={effectiveIsLoading}
            onClick={() => {
              if (onRefresh) {
                onRefresh()
                return
              }
              void recordsState.refresh()
            }}
            variant="outline"
          >
            {effectiveIsLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-4">
        {effectiveError ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {effectiveError.message}
          </div>
        ) : null}

        {effectiveIsLoading && filteredRecords.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            Loading records…
          </div>
        ) : null}

        {!effectiveIsLoading && filteredRecords.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            {emptyText}
          </div>
        ) : null}

        {filteredRecords.length > 0 && visibleColumns.length > 0 ? (
          <div className="overflow-x-auto rounded-[calc(var(--resource-radius-md)-0.2rem)] border border-[color:var(--resource-border)]">
            <table className="min-w-full border-collapse text-sm">
              <thead className="bg-[var(--resource-table-header)] text-left text-[color:var(--resource-muted-strong)]">
                <tr>
                  {selectionEnabled ? (
                    <th className="w-10 px-3 py-2 font-medium">
                      <Checkbox
                        aria-label="Select visible records"
                        checked={allVisibleSelected}
                        onCheckedChange={(checked) => toggleVisibleSelection(checked === true)}
                      />
                    </th>
                  ) : null}
                  {visibleColumns.map((columnName) => (
                    <th key={columnName} className="px-3 py-2 font-medium">
                      {columnName}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filteredRecords.map((record, index) => {
                  const rowId = getRecordId(record, recordIdField)
                  const isSelected = !!selectedRecordId && rowId === selectedRecordId

                  return (
                    <tr
                      key={rowId || index}
                      className={[
                        "border-t border-[color:var(--resource-border)] align-top text-[color:var(--resource-text)]",
                        onRowSelect ? "cursor-pointer transition-colors hover:bg-[var(--resource-table-row-hover)]" : "",
                        isSelected ? "bg-[var(--resource-table-row-selected)]" : "",
                      ].join(" ")}
                      onClick={onRowSelect ? () => onRowSelect(record) : undefined}
                    >
                      {selectionEnabled ? (
                        <td className="px-3 py-2">
                          <Checkbox
                            aria-label={`Select record ${rowId || index + 1}`}
                            checked={selectedIdSet.has(rowId)}
                            onCheckedChange={(checked) => {
                              if (!rowId) return
                              toggleRecordSelection(rowId, checked === true)
                            }}
                            onClick={(event) => event.stopPropagation()}
                          />
                        </td>
                      ) : null}
                      {visibleColumns.map((columnName) => (
                        <td key={columnName} className="max-w-[220px] px-3 py-2">
                          <div className="truncate" title={formatValue(record[columnName])}>
                            {formatValue(record[columnName])}
                          </div>
                        </td>
                      ))}
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        ) : null}

        {resolvedTotalCount > 0 && (onPreviousPage || onNextPage) ? (
          <div className="flex flex-col gap-3 border-t border-[color:var(--resource-border)] pt-4 text-sm text-[color:var(--resource-muted-strong)] md:flex-row md:items-center md:justify-between">
            <div>
              Showing {rangeStart}-{rangeEnd} of {resolvedTotalCount}
            </div>
            <div className="flex items-center gap-2">
              <Button
                disabled={pageIndex === 0}
                onClick={onPreviousPage}
                variant="outline"
              >
                Previous
              </Button>
              <div className="text-xs text-[color:var(--resource-muted)]">Page {pageIndex + 1}</div>
              <Button
                disabled={!hasNextPage}
                onClick={onNextPage}
                variant="outline"
              >
                Next
              </Button>
            </div>
          </div>
        ) : null}
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient, Table } from "lemma-sdk"
import { useBulkRecords, useRecordSchema, useRecords, useTables } from "lemma-sdk/react"
import { LemmaBulkActionsBar } from "@/components/lemma/lemma-bulk-actions-bar"
import { LemmaRecordDetailsCard } from "@/components/lemma/lemma-record-details-card"
import { LemmaRecordFiltersBar } from "@/components/lemma/lemma-record-filters-bar"
import { LemmaRecordForm } from "@/components/lemma/lemma-record-form"
import { LemmaRecordPicker } from "@/components/lemma/lemma-record-picker"
import { LemmaRecordsTable } from "@/components/lemma/lemma-records-table"
import { LemmaRelatedRecordsTable } from "@/components/lemma/lemma-related-records-table"
import { LemmaReverseRelatedRecordsTable } from "@/components/lemma/lemma-reverse-related-records-table"
import { LemmaTablePicker } from "@/components/lemma/lemma-table-picker"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

type SortFieldOption = { value: string; label: string }

export interface LemmaRecordsPageProps {
  client: LemmaClient
  podId?: string
  title?: string
  description?: string
  tables?: Table[]
  isLoadingTables?: boolean
  tablesError?: Error | null
  onRefreshTables?: () => void
  tableName?: string
  onTableNameChange?: (value: string) => void
  initialTableName?: string
  initialRecordId?: string | null
  recordLimit?: number
  showRelatedRecords?: boolean
  showReverseRelations?: boolean
  variant?: "workspace" | "browser"
}

function filterRecords(records: Record<string, unknown>[], search: string): Record<string, unknown>[] {
  const normalizedSearch = search.trim().toLowerCase()
  if (!normalizedSearch) return records

  return records.filter((record) => Object.values(record).some((value) => {
    if (typeof value === "string") return value.toLowerCase().includes(normalizedSearch)
    if (typeof value === "number" || typeof value === "boolean") return String(value).toLowerCase().includes(normalizedSearch)
    return false
  }))
}

function readRecordId(record: Record<string, unknown>): string {
  const value = record.id
  if (typeof value === "string") return value
  if (typeof value === "number") return String(value)
  return ""
}

function sentenceCase(value: string): string {
  return value
    .replace(/[_\.]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function buildSortFieldOptions(table: Table | null): SortFieldOption[] {
  if (!table) return []

  return table.columns
    .map((column) => column.name)
    .filter((name) => name !== "created_at" && name !== "updated_at")
    .map((name) => ({
      value: name,
      label: sentenceCase(name),
    }))
}

export function LemmaRecordsPage({
  client,
  podId,
  title = "Records Page",
  description = "Browse, inspect, edit, and relate table rows from one block.",
  tables,
  isLoadingTables,
  tablesError,
  onRefreshTables,
  tableName,
  onTableNameChange,
  initialTableName = "",
  initialRecordId = null,
  recordLimit = 25,
  showRelatedRecords = true,
  showReverseRelations = true,
  variant = "workspace",
}: LemmaRecordsPageProps) {
  const hasExternalTables = typeof tables !== "undefined"
  const [internalSelectedTableName, setInternalSelectedTableName] = React.useState(initialTableName)
  const [selectedRecordId, setSelectedRecordId] = React.useState(initialRecordId ?? "")
  const [recordMode, setRecordMode] = React.useState<"create" | "update">(initialRecordId ? "update" : "create")
  const [selectedRelationFieldName, setSelectedRelationFieldName] = React.useState("")
  const [selectedReverseRelationKey, setSelectedReverseRelationKey] = React.useState("")
  const [search, setSearch] = React.useState("")
  const [recordDetailsVersion, setRecordDetailsVersion] = React.useState(0)
  const [selectedRecordIds, setSelectedRecordIds] = React.useState<string[]>([])
  const [pageSize, setPageSize] = React.useState(recordLimit)
  const [offset, setOffset] = React.useState(0)
  const [sortBy, setSortBy] = React.useState("")
  const [sortOrder, setSortOrder] = React.useState<"asc" | "desc">("asc")
  const selectedTableName = tableName ?? internalSelectedTableName
  const previousTableNameRef = React.useRef(selectedTableName)

  const setSelectedTableName = React.useCallback((value: string) => {
    if (typeof tableName === "undefined") {
      setInternalSelectedTableName(value)
    }

    onTableNameChange?.(value)
  }, [onTableNameChange, tableName])

  const tablesState = useTables({
    client,
    podId,
    enabled: !hasExternalTables,
    limit: 100,
  })
  const effectiveTables = tables ?? tablesState.tables
  const effectiveTablesIsLoading = isLoadingTables ?? tablesState.isLoading
  const effectiveTablesError = tablesError ?? tablesState.error

  const recordsState = useRecords({
    client,
    podId,
    tableName: selectedTableName,
    enabled: selectedTableName.trim().length > 0,
    limit: pageSize,
    offset,
    sortBy: sortBy || undefined,
    order: sortBy ? sortOrder : undefined,
  })
  const bulkRecords = useBulkRecords({
    client,
    podId,
    tableName: selectedTableName,
    enabled: selectedTableName.trim().length > 0 && variant === "workspace",
  })

  const recordSchema = useRecordSchema({
    client,
    podId,
    tableName: selectedTableName,
    enabled: selectedTableName.trim().length > 0,
  })

  React.useEffect(() => {
    if (!selectedTableName && effectiveTables[0]?.name) {
      setSelectedTableName(effectiveTables[0].name)
    }
  }, [effectiveTables, selectedTableName, setSelectedTableName])

  React.useEffect(() => {
    if (previousTableNameRef.current === selectedTableName) {
      return
    }

    previousTableNameRef.current = selectedTableName
    setRecordMode("create")
    setSelectedRecordId("")
    setSelectedRecordIds([])
    setSelectedRelationFieldName("")
    setSelectedReverseRelationKey("")
    setSearch("")
    setOffset(0)
    setSortBy("")
    setSortOrder("asc")
    setRecordDetailsVersion((current) => current + 1)
  }, [selectedTableName])

  React.useEffect(() => {
    setOffset(0)
  }, [pageSize, sortBy, sortOrder])

  React.useEffect(() => {
    if (recordMode === "create") {
      setSelectedRecordId("")
      return
    }

    if (!selectedRecordId && recordsState.records[0]?.id) {
      setSelectedRecordId(String(recordsState.records[0].id))
    }
  }, [recordMode, recordsState.records, selectedRecordId])

  React.useEffect(() => {
    const visibleRecordIds = new Set(recordsState.records.map((record) => readRecordId(record)).filter((value) => value.length > 0))
    setSelectedRecordIds((current) => current.filter((recordIdValue) => visibleRecordIds.has(recordIdValue)))
  }, [recordsState.records])

  const filteredRecords = React.useMemo(
    () => filterRecords(recordsState.records, search),
    [recordsState.records, search],
  )

  const relationFields = React.useMemo(
    () => recordSchema.fields.filter((field) => field.foreignKey),
    [recordSchema.fields],
  )

  React.useEffect(() => {
    if (relationFields.length === 0) {
      setSelectedRelationFieldName("")
      return
    }

    setSelectedRelationFieldName((current) => (
      current && relationFields.some((field) => field.name === current)
        ? current
        : (relationFields[0]?.name ?? "")
    ))
  }, [relationFields])

  const selectedRelationField = React.useMemo(
    () => relationFields.find((field) => field.name === selectedRelationFieldName) ?? null,
    [relationFields, selectedRelationFieldName],
  )

  const relatedInclude = React.useMemo(() => {
    if (!selectedRelationField?.foreignKey) return []
    return [{ foreignKey: selectedRelationField.name }]
  }, [selectedRelationField])

  const sortFieldOptions = React.useMemo(
    () => buildSortFieldOptions(recordSchema.table),
    [recordSchema.table],
  )

  const pageIndex = Math.floor(offset / Math.max(pageSize, 1))
  const hasNextPage = !!recordsState.nextPageToken || (offset + pageSize < recordsState.total)

  const handleDeleteSelected = React.useCallback(async () => {
    if (selectedRecordIds.length === 0) return

    const nextOffset = offset > 0 && selectedRecordIds.length >= recordsState.records.length
      ? Math.max(0, offset - pageSize)
      : offset

    const response = await bulkRecords.deleteMany(selectedRecordIds)
    if (!response) return

    if (selectedRecordIds.includes(selectedRecordId)) {
      setSelectedRecordId("")
      setRecordMode("create")
      setRecordDetailsVersion((current) => current + 1)
    }

    setSelectedRecordIds([])
    if (nextOffset !== offset) {
      setOffset(nextOffset)
    }

    await recordsState.refresh({
      limit: pageSize,
      offset: nextOffset,
      sortBy: sortBy || undefined,
      order: sortBy ? sortOrder : undefined,
    })
  }, [
    bulkRecords,
    offset,
    pageSize,
    recordsState,
    selectedRecordId,
    selectedRecordIds,
    sortBy,
    sortOrder,
  ])

  return (
    <div className="grid min-w-0 gap-6">
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <CardContent className="grid gap-4">
          <LemmaTablePicker
            client={client}
            description="Choose the active table for this records workspace."
            error={effectiveTablesError}
            isLoading={effectiveTablesIsLoading}
            onRefresh={() => {
              if (onRefreshTables) {
                onRefreshTables()
                return
              }
              void tablesState.refresh()
            }}
            onValueChange={setSelectedTableName}
            podId={podId}
            tables={effectiveTables}
            title="Active Table"
            value={selectedTableName}
          />

          <LemmaRecordFiltersBar
            availableSortFields={sortFieldOptions}
            isRefreshing={recordsState.isLoading}
            onPageSizeChange={setPageSize}
            onRefresh={() => {
              void recordsState.refresh()
            }}
            onSearchChange={setSearch}
            onSortByChange={setSortBy}
            onSortOrderChange={setSortOrder}
            pageSize={pageSize}
            resultCount={search.trim().length > 0 ? filteredRecords.length : recordsState.total}
            search={search}
            sortBy={sortBy}
            sortOrder={sortOrder}
          />

          {variant === "workspace" ? (
            <LemmaBulkActionsBar
              error={bulkRecords.error}
              isDeleting={bulkRecords.isSubmitting}
              message={bulkRecords.lastMessage}
              onClearSelection={() => setSelectedRecordIds([])}
              onDeleteSelected={() => {
                void handleDeleteSelected()
              }}
              selectedCount={selectedRecordIds.length}
            />
          ) : null}

          <div className="grid min-w-0 gap-4 md:grid-cols-[minmax(0,1fr)_220px]">
            <LemmaRecordPicker
              client={client}
              description="Quick-jump to a record in the current table."
              isLoading={recordsState.isLoading}
              onRefresh={() => {
                void recordsState.refresh()
              }}
              onSearchChange={setSearch}
              onValueChange={(value) => {
                setRecordMode("update")
                setSelectedRecordId(value)
              }}
              podId={podId}
              records={recordsState.records}
              search={search}
              tableName={selectedTableName}
              title="Record Picker"
              value={selectedRecordId}
            />

            <div className="grid gap-2">
              <p className="text-sm font-medium text-[color:var(--resource-text)]">Mode</p>
              <Select value={recordMode} onValueChange={(value) => setRecordMode(value as "create" | "update")}>
                <SelectTrigger id="lemma-records-page-mode">
                  <SelectValue placeholder="Select mode" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="create">Create new record</SelectItem>
                  <SelectItem value="update">Edit existing record</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <LemmaRecordsTable
        client={client}
        description="Click a row to move the form and details panel to that record."
        hasNextPage={hasNextPage}
        isLoading={recordsState.isLoading}
        onNextPage={() => setOffset((current) => current + pageSize)}
        onPreviousPage={() => setOffset((current) => Math.max(0, current - pageSize))}
        onRefresh={() => {
          void recordsState.refresh()
        }}
        onRowSelect={(record) => {
          setRecordMode("update")
          setSelectedRecordId(String(record.id ?? ""))
        }}
        onSelectedRecordIdsChange={variant === "workspace" ? setSelectedRecordIds : undefined}
        pageIndex={pageIndex}
        pageSize={pageSize}
        podId={podId}
        records={recordsState.records}
        search={search}
        selectedRecordId={recordMode === "update" ? selectedRecordId : null}
        selectedRecordIds={selectedRecordIds}
        showSelection={variant === "workspace"}
        tableName={selectedTableName}
        title="Records Table"
        totalCount={recordsState.total}
      />

      <div className={variant === "workspace" ? "grid min-w-0 gap-6 xl:grid-cols-[minmax(0,1fr)_minmax(0,1fr)]" : "grid min-w-0 gap-6"}>
        <LemmaRecordDetailsCard
          client={client}
          key={`${selectedTableName}:${selectedRecordId}:${recordDetailsVersion}`}
          description={recordMode === "update" ? "Inspect the current row." : "Switch to update mode to inspect a record."}
          podId={podId}
          recordId={recordMode === "update" ? selectedRecordId || null : null}
          tableName={selectedTableName}
          title="Record Details"
        />

        {variant === "workspace" ? (
          <LemmaRecordForm
            client={client}
            description={
              selectedTableName
                ? `Schema-aware form for ${selectedTableName}. ${recordSchema.editableFields.length} editable fields available.`
                : "Select a table to start editing records."
            }
            mode={recordMode}
            onSubmitted={() => {
              void recordsState.refresh({
                limit: pageSize,
                offset,
                sortBy: sortBy || undefined,
                order: sortBy ? sortOrder : undefined,
              })
              setRecordDetailsVersion((current) => current + 1)
            }}
            podId={podId}
            recordId={recordMode === "update" ? selectedRecordId || null : null}
            submitLabel={recordMode === "update" ? "Update record" : "Create record"}
            tableName={selectedTableName}
            title="Record Form"
          />
        ) : null}
      </div>

      {showRelatedRecords ? (
        <div className="grid gap-4">
          {relationFields.length > 1 ? (
            <Card>
              <CardHeader>
                <CardTitle>Forward Relation Picker</CardTitle>
                <CardDescription>Choose which foreign-key relationship to preview from the active table.</CardDescription>
              </CardHeader>
              <CardContent>
                <Select value={selectedRelationFieldName} onValueChange={setSelectedRelationFieldName}>
                  <SelectTrigger id="lemma-records-page-relation">
                    <SelectValue placeholder="Select a relation" />
                  </SelectTrigger>
                  <SelectContent>
                    {relationFields.map((field) => (
                      <SelectItem key={field.name} value={field.name}>
                        {field.foreignKey ? `${field.name} -> ${field.foreignKey.table}` : field.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </CardContent>
            </Card>
          ) : null}

          <LemmaRelatedRecordsTable
            client={client}
            description={
              selectedRelationField?.foreignKey
                ? `Following ${selectedTableName}.${selectedRelationField.name} into ${selectedRelationField.foreignKey.table}.`
                : "Choose a table with a foreign key to preview related data."
            }
            include={relatedInclude}
            podId={podId}
            tableName={selectedTableName}
            title="Related Records"
          />
        </div>
      ) : null}

      {showReverseRelations ? (
        <LemmaReverseRelatedRecordsTable
          client={client}
          description="Child rows discovered from other tables that reference the currently selected record."
          onRelationChange={(relationValue) => {
            setSelectedReverseRelationKey(
              relationValue ? `${relationValue.tableName}:${relationValue.foreignKey}` : "",
            )
          }}
          podId={podId}
          recordId={recordMode === "update" ? selectedRecordId || null : null}
          relation={selectedReverseRelationKey
            ? {
                tableName: selectedReverseRelationKey.split(":")[0] ?? "",
                foreignKey: selectedReverseRelationKey.split(":")[1] ?? "",
              }
            : null}
          tableName={selectedTableName}
          title="Reverse Related Records"
        />
      ) : null}
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRelatedRecords, type RelatedRecordsInclude } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"

export interface LemmaRelatedRecordsTableProps {
  client: LemmaClient
  podId?: string
  tableName: string
  include: RelatedRecordsInclude[]
  baseFields?: string[]
  limit?: number
  title?: string
  description?: string
  emptyText?: string
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function readColumnValue(record: Record<string, unknown>, column: {
  source: "base" | "related"
  field: string
  relationKey?: string
}): unknown {
  if (column.source === "base") {
    return record[column.field]
  }

  const relatedRecord = column.relationKey ? record[column.relationKey] : undefined
  if (!relatedRecord || typeof relatedRecord !== "object" || Array.isArray(relatedRecord)) {
    return undefined
  }

  return (relatedRecord as Record<string, unknown>)[column.field]
}

export function LemmaRelatedRecordsTable({
  client,
  podId,
  tableName,
  include,
  baseFields,
  limit = 10,
  title,
  description,
  emptyText = "No related records were found for this relation setup.",
}: LemmaRelatedRecordsTableProps) {
  const trimmedTableName = tableName.trim()
  const relatedState = useRelatedRecords({
    client,
    podId,
    tableName: trimmedTableName,
    include,
    baseFields,
    limit,
    enabled: trimmedTableName.length > 0 && include.length > 0,
  })

  if (!trimmedTableName || include.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Related Records"}</CardTitle>
          <CardDescription>{description ?? "Choose a table with a foreign key to preview related data."}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title ?? `Related Records: ${trimmedTableName}`}</CardTitle>
            <CardDescription>
              {description ?? "Relation-aware joined records powered by foreign-key metadata."}
            </CardDescription>
          </div>
          <Button
            disabled={relatedState.isLoading}
            onClick={() => {
              void relatedState.refresh()
            }}
            variant="outline"
          >
            {relatedState.isLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-4">
        {relatedState.error ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {relatedState.error.message}
          </div>
        ) : null}

        {relatedState.isLoading && relatedState.records.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            Loading related records…
          </div>
        ) : null}

        {!relatedState.isLoading && relatedState.records.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            {emptyText}
          </div>
        ) : null}

        {relatedState.records.length > 0 && relatedState.columns.length > 0 ? (
          <div className="overflow-x-auto rounded-[calc(var(--resource-radius-md)-0.2rem)] border border-[color:var(--resource-border)]">
            <table className="min-w-full border-collapse text-sm">
              <thead className="bg-[var(--resource-table-header)] text-left text-[color:var(--resource-muted-strong)]">
                <tr>
                  {relatedState.columns.map((column) => (
                    <th key={column.key} className="px-3 py-2 font-medium">
                      {column.label}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {relatedState.records.map((record, index) => (
                  <tr key={index} className="border-t border-[color:var(--resource-border)] align-top text-[color:var(--resource-text)]">
                    {relatedState.columns.map((column) => {
                      const value = readColumnValue(record, column)
                      return (
                        <td key={column.key} className="max-w-[220px] px-3 py-2">
                          <div className="truncate" title={formatValue(value)}>
                            {formatValue(value)}
                          </div>
                        </td>
                      )
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : null}
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useReverseRelatedRecords, type ReverseRelationSelector } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

export interface LemmaReverseRelatedRecordsTableProps {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  relation?: ReverseRelationSelector | null
  onRelationChange?: (relation: ReverseRelationSelector | null) => void
  fields?: string[]
  limit?: number
  title?: string
  description?: string
  emptyText?: string
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "—"

  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

export function LemmaReverseRelatedRecordsTable({
  client,
  podId,
  tableName,
  recordId,
  relation,
  onRelationChange,
  fields,
  limit = 10,
  title,
  description,
  emptyText = "No child records were found for this record.",
}: LemmaReverseRelatedRecordsTableProps) {
  const trimmedTableName = tableName.trim()
  const trimmedRecordId = typeof recordId === "string" ? recordId.trim() : ""
  const reverseState = useReverseRelatedRecords({
    client,
    podId,
    tableName: trimmedTableName,
    recordId: trimmedRecordId || null,
    relation,
    fields,
    limit,
    enabled: trimmedTableName.length > 0 && trimmedRecordId.length > 0,
  })

  if (!trimmedTableName || !trimmedRecordId) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>{title ?? "Reverse Related Records"}</CardTitle>
          <CardDescription>{description ?? "Select a record to inspect child rows that point back to it."}</CardDescription>
        </CardHeader>
      </Card>
    )
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title ?? "Reverse Related Records"}</CardTitle>
            <CardDescription>
              {description ?? "Child rows discovered from foreign keys that reference this record's table."}
            </CardDescription>
          </div>
          <Button
            disabled={reverseState.isLoading}
            onClick={() => {
              void reverseState.refresh()
            }}
            variant="outline"
          >
            {reverseState.isLoading ? "Refreshing…" : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-4">
        {reverseState.relations.length > 1 ? (
          <Select
            value={reverseState.selectedRelation ? `${reverseState.selectedRelation.tableName}:${reverseState.selectedRelation.foreignKey}` : ""}
            onValueChange={(value) => {
              const [tableNameValue, foreignKeyValue] = value.split(":")
              onRelationChange?.(
                tableNameValue && foreignKeyValue
                  ? { tableName: tableNameValue, foreignKey: foreignKeyValue }
                  : null,
              )
            }}
          >
            <SelectTrigger id="lemma-reverse-related-relation">
              <SelectValue placeholder="Select a reverse relation" />
            </SelectTrigger>
            <SelectContent>
              {reverseState.relations.map((entry) => (
                <SelectItem key={`${entry.tableName}:${entry.foreignKey}`} value={`${entry.tableName}:${entry.foreignKey}`}>
                  {entry.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        ) : null}

        {reverseState.error ? (
          <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
            {reverseState.error.message}
          </div>
        ) : null}

        {reverseState.isLoading && reverseState.records.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            Loading reverse-related records…
          </div>
        ) : null}

        {!reverseState.isLoading && reverseState.relations.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            No reverse relations were discovered for this table.
          </div>
        ) : null}

        {!reverseState.isLoading && reverseState.relations.length > 0 && reverseState.records.length === 0 ? (
          <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
            {emptyText}
          </div>
        ) : null}

        {reverseState.records.length > 0 && reverseState.columns.length > 0 ? (
          <div className="overflow-x-auto rounded-[calc(var(--resource-radius-md)-0.2rem)] border border-[color:var(--resource-border)]">
            <table className="min-w-full border-collapse text-sm">
              <thead className="bg-[var(--resource-table-header)] text-left text-[color:var(--resource-muted-strong)]">
                <tr>
                  {reverseState.columns.map((column) => (
                    <th key={column.key} className="px-3 py-2 font-medium">
                      {column.label}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {reverseState.records.map((record, index) => (
                  <tr key={String(record.id ?? index)} className="border-t border-[color:var(--resource-border)] align-top text-[color:var(--resource-text)]">
                    {reverseState.columns.map((column) => (
                      <td key={column.key} className="max-w-[220px] px-3 py-2">
                        <div className="truncate" title={formatValue(record[column.field])}>
                          {formatValue(record[column.field])}
                        </div>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : null}
      </CardContent>
    </Card>
  )
}
